const farmId = msg.req.params.farmId;
const houseId = msg.req.params.houseId;

msg.topic = `SELECT sensor_id, value, timestamp
FROM sensor_data
WHERE farm_id = $farmId AND house_id = $houseId
AND timestamp = (
  SELECT MAX(timestamp) FROM sensor_data
  WHERE farm_id = $farmId AND house_id = $houseId
)
ORDER BY sensor_id`;
msg.params = { $farmId: farmId, $houseId: houseId };

msg._farmId = farmId;
msg._houseId = houseId;
return msg;

const rows = msg.payload || [];
const data = {};
let timestamp = null;

for (const row of rows) {
    data[row.sensor_id] = row.value;
    timestamp = row.timestamp;
}

msg.payload = {
    success: true,
    data: {
        farmId: msg._farmId,
        houseId: msg._houseId,
        data: data,
        timestamp: timestamp,
        source: 'sqlite'
    }
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

const farmId = msg.req.params.farmId;
const houseId = msg.req.params.houseId;
const startDate = msg.req.query.startDate || new Date(Date.now() - 24*60*60*1000).toISOString();
const endDate = msg.req.query.endDate || new Date().toISOString();
const limit = Math.min(parseInt(msg.req.query.limit) || 1000, 10000);

msg.topic = `SELECT sensor_id, value, timestamp
FROM sensor_data
WHERE farm_id = $farmId AND house_id = $houseId
AND timestamp BETWEEN $startDate AND $endDate
ORDER BY timestamp ASC
LIMIT $limit`;
msg.params = { $farmId: farmId, $houseId: houseId, $startDate: startDate, $endDate: endDate, $limit: limit };

msg._farmId = farmId;
msg._houseId = houseId;
return msg;

const rows = msg.payload || [];

// 타임스탬프별로 그룹핑 (서버 응답 형식 맞춤)
const grouped = {};
for (const row of rows) {
    if (!grouped[row.timestamp]) {
        grouped[row.timestamp] = {
            timestamp: row.timestamp,
            farmId: msg._farmId,
            houseId: msg._houseId,
            data: {}
        };
    }
    grouped[row.timestamp].data[row.sensor_id] = row.value;
}

msg.payload = {
    success: true,
    data: Object.values(grouped),
    source: 'sqlite'
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

const farmId = msg.req.params.farmId;
const houseId = msg.req.params.houseId;
const today = new Date();
today.setHours(0, 0, 0, 0);

msg.topic = `SELECT COUNT(DISTINCT timestamp) as count
FROM sensor_data
WHERE farm_id = $farmId AND house_id = $houseId
AND timestamp >= $today`;
msg.params = { $farmId: farmId, $houseId: houseId, $today: today.toISOString() };

return msg;

const rows = msg.payload || [];
const count = rows[0] ? rows[0].count : 0;

msg.payload = {
    success: true,
    count: count,
    source: 'sqlite'
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

const farmId = msg.req.params.farmId;
const houseId = msg.req.query.houseId;

if (houseId) {
    msg.topic = `SELECT id, timestamp, device_id, command, source
FROM control_logs
WHERE source = 'automation' AND device_id LIKE $housePattern
ORDER BY timestamp DESC
LIMIT 50`;
    msg.params = { $housePattern: houseId + '%' };
} else {
    msg.topic = `SELECT id, timestamp, device_id, command, source
FROM control_logs
WHERE source = 'automation'
ORDER BY timestamp DESC
LIMIT 50`;
    msg.params = {};
}

return msg;

const rows = msg.payload || [];

const alerts = rows.map(row => ({
    id: row.id,
    timestamp: row.timestamp,
    type: 'automation',
    message: `${row.device_id} ${row.command} (${row.source})`,
    deviceId: row.device_id,
    command: row.command,
    source: row.source
}));

msg.payload = {
    success: true,
    data: alerts,
    source: 'sqlite'
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

const { house_id, device_id, command, operator } = msg.payload;

// 입력 검증
if (!device_id || !command) {
    msg.payload = { success: false, error: 'device_id, command 필수' };
    msg.statusCode = 400;
    msg.headers = { 'Access-Control-Allow-Origin': '*' };
    return [msg, null, null];
}

// 허용된 명령어만 통과
const ALLOWED_COMMANDS = ['open', 'close', 'stop', 'on', 'off'];
if (!ALLOWED_COMMANDS.includes(command)) {
    msg.payload = { success: false, error: '허용되지 않는 명령: ' + command };
    msg.statusCode = 400;
    msg.headers = { 'Access-Control-Allow-Origin': '*' };
    return [msg, null, null];
}

// device_id 형식 검증 (영숫자+언더스코어만)
if (!/^[a-zA-Z0-9_]+$/.test(device_id)) {
    msg.payload = { success: false, error: '잘못된 device_id 형식' };
    msg.statusCode = 400;
    msg.headers = { 'Access-Control-Allow-Origin': '*' };
    return [msg, null, null];
}

const houseId = house_id || 'house1';
const ts = new Date().toISOString();
const requestId = `local_${Date.now()}`;

// GPIO 제어 메시지 생성
const controlMsg = {
    control: {
        houseId: houseId,
        deviceId: device_id,
        deviceType: device_id.replace(/[0-9]/g, ''),
        command: command,
        operator: operator || 'local_dashboard',
        requestId: requestId,
        timestamp: ts
    }
};

// SQLite 로그 저장 (msg.topic 모드: $1,$2,.. 위치 파라미터 + msg.payload 배열)
var logMsg = {};
logMsg.topic = 'INSERT INTO control_logs (timestamp, device_id, command, source, synced) VALUES ($1, $2, $3, $4, 0)';
logMsg.payload = [ts, device_id, command, 'local'];

// HTTP 응답
msg.payload = {
    success: true,
    data: {
        request_id: requestId,
        device_id: device_id,
        command: command,
        executed_at: ts,
        mode: 'local'
    }
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };

node.warn(`🎮 로컬 제어: ${device_id} ${command} by ${operator || 'local'}`);

return [msg, controlMsg, logMsg];

const mode = global.get('operationMode') || 'offline';
const serverOnline = global.get('serverOnline') || false;
const manual = global.get('manualOverride') || false;

msg.payload = {
    status: 'ok',
    mode: mode,
    serverOnline: serverOnline,
    manualOverride: manual,
    source: 'node-red',
    timestamp: new Date().toISOString()
};
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

// global context에서 캐시된 설정 반환
const config = global.get('houseConfig');

if (config) {
    msg.payload = {
        success: true,
        data: config,
        source: 'cache'
    };
} else {
    msg.payload = {
        success: false,
        error: '캐시된 설정 없음'
    };
    msg.statusCode = 404;
}
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

msg.headers = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, x-api-key, Authorization'
};
msg.payload = '';
msg.statusCode = 204;
return msg;
